# JavaScript Debounce 函数

防抖（debounce）的核心思想：**在事件被连续触发时，只有最后一次（或第一次）操作在等待一定时间后才会执行**。常用于搜索输入、窗口 resize 等场景。

## 标准实现（带 leading/trailing 选项）

```javascript
/**
 * 创建一个防抖函数
 * @param {Function} fn      要执行的原始函数
 * @param {number}   delay   延迟时间（毫秒）
 * @param {Object}   options
 * @param {boolean}  options.leading  是否在延迟开始前立即执行（默认 false）
 * @param {boolean}  options.trailing 是否在延迟结束后执行（默认 true）
 * @returns {Function} 防抖后的函数
 */
function debounce(fn, delay = 300, options = {}) {
  const { leading = false, trailing = true } = options;

  let timer = null;           // 定时器句柄
  let lastArgs = null;       // 最后一次调用的参数
  let lastThis = null;       // 最后一次调用的 this
  let isLeadingCalled = false; // leading 是否已执行（用于防重复）

  function invoke(timeType) {
    if (timeType === 'leading') {
      isLeadingCalled = true;
      fn.apply(lastThis, lastArgs);
    }
    if (timeType === 'trailing') {
      fn.apply(lastThis, lastArgs);
    }
    // 清理状态
    lastThis = null;
    lastArgs = null;
  }

  function debounced(...args) {
    const context = this;     // 保留调用者 this
    lastArgs = args;
    lastThis = context;

    // 如果已有定时器，清除它（重新计时）
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }

    // leading 模式：首次触发时立即执行
    if (leading && !isLeadingCalled) {
      invoke('leading');
    }

    // trailing 模式：延迟结束后执行（默认行为）
    if (trailing) {
      timer = setTimeout(() => {
        // 只有 trailing 与 leading 不重叠时才执行
        // 如果 leading 执行过且没有新的调用，不再重复执行
        if (leading) {
          isLeadingCalled = false;
        }
        invoke('trailing');
        timer = null;
      }, delay);
    }
  }

  /**
   * 取消防抖，取消尚未执行的 trailing 调用
   */
  debounced.cancel = function () {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    isLeadingCalled = false;
    lastArgs = null;
    lastThis = null;
  };

  /**
   * 立即执行并取消防抖
   */
  debounced.flush = function () {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    if (lastArgs) {
      fn.apply(lastThis, lastArgs);
      lastArgs = null;
      lastThis = null;
    }
    isLeadingCalled = false;
  };

  return debounced;
}
```

## 简洁版（日常最常用）

```javascript
function debounce(fn, delay = 300) {
  let timer = null;
  return function (...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  };
}
```

## 使用示例

```javascript
// ---------- 搜索输入防抖 ----------
const searchInput = document.getElementById('search');

const handleSearch = debounce((event) => {
  console.log('发起搜索:', event.target.value);
  // 调用搜索 API ...
}, 500);

searchInput.addEventListener('input', handleSearch);


// ---------- window resize 防抖 ----------
const handleResize = debounce(() => {
  console.log('窗口大小变化完成，重新计算布局');
}, 300);

window.addEventListener('resize', handleResize);


// ---------- leading + trailing 组合 ----------
// 按钮防连点：第一次立即执行，之后 2 秒内不重复
const saveBtn = document.getElementById('save');

const handleSave = debounce(
  () => console.log('保存数据...'),
  2000,
  { leading: true, trailing: false }
);

saveBtn.addEventListener('click', handleSave);


// ---------- 取消 / 立即执行 ----------
const logFn = debounce(() => console.log('执行了'), 1000);
logFn();
logFn.cancel();   // 取消未执行的回调

logFn();
logFn.flush();    // 立即执行
```

## 关键要点

| 模式 | 行为 | 适用场景 |
|------|------|----------|
| `trailing: true`（默认） | 停止触发后 delay 毫秒执行 | 搜索输入、resize |
| `leading: true` | 首次触发时立即执行，之后忽略 | 按钮防连点 |
| 两者都 true | 首次立即执行 + 最后一次延迟执行 | 自动保存（首次立即保存，之后防抖） |

## 对比节流（Throttle）

| | Debounce | Throttle |
|--|----------|----------|
| 行为 | 延迟执行，连续触发会重置计时 | 固定频率执行，不重置 |
| 适合 | 输入搜索、resize | 滚动事件、mousemove |

